input.new_string:
const users = [
  { id: 1, name: 'Alice', email: 'alice@example.com' },
  { id: 2, name: 'Bob', email: 'bob@example.com' },
];

app.get('/users', (req, res) => {
  res.json(users);
});

app.get('/users/:id', (req, res) => {
  const { id } = req.params;

  // Validate that the id is a positive integer (non-numeric or malformed
  // values previously caused an unhandled TypeError downstream).
  if (!/^\d+$/.test(id)) {
    return res.status(400).json({
      error: 'Bad Request',
      message: `Invalid user id "${id}": id must be a positive integer.`,
    });
  }

  const numericId = Number.parseInt(id, 10);
  if (!Number.isSafeInteger(numericId) || numericId < 1) {
    return res.status(400).json({
      error: 'Bad Request',
      message: `Invalid user id "${id}": id must be a positive integer.`,
    });
  }

  const user = users.find((u) => u.id === numericId);
  if (!user) {
    return res.status(404).json({
      error: 'Not Found',
      message: `User with id ${numericId} does not exist.`,
    });
  }

  res.json(user);
});

